#!/usr/bin/perl
use strict;
use warnings;
use PDF::API2;
use Text::Unidecode;

# Function to extract text from a PDF page
sub extract_text {
    my ($page) = @_;
    my $text = $page->textout();
    return $text;
}

# Function to extract specific information
sub extract_info {
    my ($pdf, $page_num) = @_;
    my $page = $pdf->page($page_num);
    my $text = extract_text($page);

    # Extract author
    if ($text =~ /Author:\s*(.*)/i) {
        return $1;
    }

    # Extract date
    if ($text =~ /Date:\s*(.*)/i) {
        return $1;
    }

    # Extract table information (example: extracting a single row)
    if ($text =~ /Table\s+1\s+(.*)/i) {
        return $1;
    }

    return 'No specific information found';
}

# Main script
my $pdf_file = 'example.pdf'; # Replace with your PDF file
my $pdf = PDF::API2->open($pdf_file);

for (my $i = 1; $i <= $pdf->pages; $i++) {
    my $info = extract_info($pdf, $i);
    print "Page $i: $info\n";
}
